import{_ as n,C as o,o as l,c as s,E as a,w as t,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const v=JSON.parse('{"title":"Latvia Legal Rights","description":"Legal rights for transgender people in Latvia","frontmatter":{"layout":"doc","title":"Latvia Legal Rights","description":"Legal rights for transgender people in Latvia"},"headers":[],"relativePath":"europe/latvia/legal-rights.md","filePath":"europe/latvia/legal-rights.md","lastUpdated":null}'),c={name:"europe/latvia/legal-rights.md"};function g(h,e,u,m,p,f){const i=o("Badge");return l(),s("div",null,[a(i,{variant:"red"},{default:t(()=>[...e[0]||(e[0]=[r("Surgery Required",-1)])]),_:1}),a(i,{variant:"yellow"},{default:t(()=>[...e[1]||(e[1]=[r("Anti-Discrimination Laws",-1)])]),_:1}),a(i,{variant:"red"},{default:t(()=>[...e[2]||(e[2]=[r("No Explicit Hate Crime Law",-1)])]),_:1}),e[3]||(e[3]=d('<h1 id="legal-rights-in-latvia" tabindex="-1">Legal Rights in Latvia <a class="header-anchor" href="#legal-rights-in-latvia" aria-label="Permalink to &quot;Legal Rights in Latvia&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Latvia has one of the <strong>most restrictive</strong> gender recognition systems in the EU:</p><ul><li><strong>Requirements</strong>: Diagnosis of gender dysphoria + sex reassignment surgery (sterilization implied)</li><li><strong>Medical Assessment</strong>: A multi-disciplinary medical commission evaluates applications</li><li><strong>Age</strong>: 18+ only</li><li><strong>Process</strong>: Application to the Medical Committee for Gender Change (under the Ministry of Health); surgery must be completed before legal gender change is approved</li><li><strong>Surgery</strong>: Legally required — no alternative pathway exists</li></ul><h3 id="the-process" tabindex="-1">The Process <a class="header-anchor" href="#the-process" aria-label="Permalink to &quot;The Process&quot;">​</a></h3><ol><li>Referral to a psychiatrist specializing in gender dysphoria</li><li>Diagnosis from the medical commission</li><li>Mandatory real-life experience period</li><li>Sex reassignment surgery (must be completed)</li><li>Apply to the Civil Registry for gender marker change</li><li>Updated passport and ID card</li></ol><p><strong>Note</strong>: Latvian law effectively mandates sterilization. This has been criticized by international human rights bodies including the Council of Europe.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><ul><li>Name changes may be possible without full gender recognition</li><li>Processed through the <strong>Civil Registry</strong> (Dzimtsarakstu nodaļa)</li><li>Requires a valid reason; gender transition is generally accepted as valid</li><li>Simpler than gender marker change but still bureaucratic</li></ul><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><ul><li><strong>Employment</strong>: Prohibited under the Labour Law (based on EU directives)</li><li><strong>Goods and Services</strong>: Protected under the Consumer Rights Protection Law</li><li><strong>Education</strong>: General equality provisions apply</li></ul><p>The <strong>Equal Treatment Law</strong> prohibits discrimination based on sexual orientation but does not explicitly mention gender identity. Enforcement is weak, and few cases are brought.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><ul><li>Latvia does <strong>not</strong> have explicit hate crime legislation covering gender identity</li><li>The Criminal Law includes enhanced penalties for crimes motivated by racial, national, or religious hatred</li><li>Proposals to add sexual orientation and gender identity have been repeatedly rejected by parliament</li><li>Some local advocacy organizations monitor transphobic incidents</li></ul><h2 id="document-recognition" tabindex="-1">Document Recognition <a class="header-anchor" href="#document-recognition" aria-label="Permalink to &quot;Document Recognition&quot;">​</a></h2><ul><li>Updated passports reflect the new gender marker once the medical process is complete</li><li>ID cards and driver&#39;s licenses can be updated accordingly</li><li>Previous records remain in the system but are not publicly accessible</li><li>EU travel documents are recognized within the Schengen Area</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.vm.gov.lv/" target="_blank" rel="noreferrer">Latvian Ministry of Health</a></li><li><a href="https://www.mozaika.lv/" target="_blank" rel="noreferrer">Mozaika (LGBTQ+ Organization)</a></li><li><a href="https://www.baltipride.com/" target="_blank" rel="noreferrer">Baltic Pride</a></li><li><a href="https://www.coe.int/" target="_blank" rel="noreferrer">Council of Europe - LGBTI in Latvia</a></li></ul>',18))])}const y=n(c,[["render",g]]);export{v as __pageData,y as default};
